def _parse_many(json_strs: list[str]) -> list[dict]:
    out: list[dict] = []
    for s in json_strs:
        arr = json.loads(s)
        for it in arr:
            if not isinstance(it, dict):
                continue
            if "资讯标题" not in it or "日期" not in it:
                continue
            out.append(it)
    return out


def _lines(items: list[dict]) -> list[str]:
    seen: set[tuple[str, str]] = set()
    lines: list[str] = []
    for it in items:
        d = str(it.get("日期", "")).strip()
        t = str(it.get("资讯标题", "")).strip()
        if not d or not t:
            continue
        key = (d, t)
        if key in seen:
            continue
        seen.add(key)
        lines.append(f"{d} | {t}")
    return lines


def main() -> None:
    macro = {
        "policy": _lines(_parse_many(RAW_BLOCKS["policy"])),
        "global_liquidity": _lines(_parse_many(RAW_BLOCKS["global_liquidity"])),
        "summary": "上述 policy / global_liquidity 数组已合并三轮 search_news（货币政策国常会央行；美元流动性人民币汇率），按「日期+标题」去重，条目与 MCP 返回一一对应，无摘要替代。",
    }
    meso = {
        "tech": _lines(_parse_many(RAW_BLOCKS["tech"])),
        "property": _lines(_parse_many(RAW_BLOCKS["property"])),
        "summary": "tech 合并「行业景气 开工率 制造业投资」与「制造业 景气 投资 开工」两轮；property 为「房地产 商品房 成交 30城」单轮全量；均按日期+标题去重。",
    }
    micro = {
        "earnings": _lines(_parse_many(RAW_BLOCKS["earnings"])),
        "event_risk": _lines(_parse_many(RAW_BLOCKS["event_risk"])),
        "summary": "earnings 合并「A股 增持 回购 分红」与「业绩预告 增持 回购 龙头」两轮；event_risk 为「美联储 FOMC 利率」单轮全量；均按日期+标题去重。",
    }
    OUT.mkdir(parents=True, exist_ok=True)
    (OUT / "MacroNews.json").write_text(
        json.dumps(macro, ensure_ascii=False, indent=2) + "\n", encoding="utf-8"
    )
    (OUT / "MesoNews.json").write_text(
        json.dumps(meso, ensure_ascii=False, indent=2) + "\n", encoding="utf-8"
    )
    (OUT / "MicroNews.json").write_text(
        json.dumps(micro, ensure_ascii=False, indent=2) + "\n", encoding="utf-8"
    )
    print("Wrote", OUT / "MacroNews.json", "lines", len(macro["policy"]), len(macro["global_liquidity"]))
    print("Wrote", OUT / "MesoNews.json", "lines", len(meso["tech"]), len(meso["property"]))
    print("Wrote", OUT / "MicroNews.json", "lines", len(micro["earnings"]), len(micro["event_risk"]))


if __name__ == "__main__":
    main()
